"use client";

import Link from "next/link";
import { GraduationCap, LayoutDashboard, Search, Bell, User } from "lucide-react";

export default function Navbar() {
    return (
        <nav className="fixed top-0 w-full z-50 px-6 py-4">
            <div className="max-w-7xl mx-auto glass-panel px-6 py-3 flex items-center justify-between">
                <Link href="/" className="flex items-center gap-2 group">
                    <div className="w-10 h-10 bg-brand-primary rounded-xl flex items-center justify-center shadow-lg shadow-brand-primary/20 group-hover:rotate-6 transition-transform">
                        <GraduationCap className="text-white w-6 h-6" />
                    </div>
                    <span className="text-xl font-bold tracking-tight">SmartPath <span className="text-brand-primary">AI</span></span>
                </Link>

                <div className="hidden md:flex items-center gap-8">
                    <Link href="/" className="text-sm font-medium hover:text-brand-primary transition-colors">Home</Link>
                    <Link href="/diagnostic" className="text-sm font-medium hover:text-brand-primary transition-colors">Diagnostic</Link>
                    <Link href="#" className="text-sm font-medium opacity-40 cursor-not-allowed">Dashboard</Link>
                    <Link href="#" className="text-sm font-medium opacity-40 cursor-not-allowed">Subjects</Link>
                </div>

                <div className="flex items-center gap-4">
                    <button className="p-2 hover:bg-white/5 rounded-full transition-colors">
                        <Search className="w-5 h-5 text-white/60" />
                    </button>
                    <button className="p-2 hover:bg-white/5 rounded-full transition-colors relative">
                        <Bell className="w-5 h-5 text-white/60" />
                        <span className="absolute top-2 right-2 w-2 h-2 bg-brand-accent rounded-full border border-black"></span>
                    </button>
                    <div className="w-10 h-10 bg-white/5 rounded-full flex items-center justify-center border border-white/10 cursor-pointer hover:bg-white/10">
                        <User className="w-5 h-5 text-white/60" />
                    </div>
                </div>
            </div>
        </nav>
    );
}
